SELECT SUM(a.balance) AS total_balance
FROM accounts a
JOIN client_accounts ca ON a.account_id = ca.account_id;

SELECT SUM(balance) AS total_balance
FROM accounts
WHERE account_type_id = (SELECT account_type_id FROM account_types WHERE account_type_name = 'Current Assets');

SELECT MIN(account_type_code) AS min_account_type_code
FROM account_types
WHERE is_active = 1;
